import { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { useNavigate } from "react-router-dom";

export default function Following() {
  const [user, setUser] = useState(null);
  const [following, setFollowing] = useState([]);
  const [projectFollowing, setProjectFollowing] = useState([]); // ✅ NEW

  const navigate = useNavigate();

  useEffect(() => {
    init();
  }, []);

  const init = async () => {
    const { data } = await supabase.auth.getUser();
    const currentUser = data.user;

    if (!currentUser) return;

    setUser(currentUser);

    fetchFollowing(currentUser.id);
    fetchProjectFollowing(currentUser.id); // ✅ NEW
  };

  // 🔥 FETCH FOLLOWING USERS
  const fetchFollowing = async (userId) => {
    const { data, error } = await supabase
      .from("follows")
      .select("*")
      .eq("follower_id", userId);

    if (error) {
      console.log(error);
      return;
    }

    if (!data || data.length === 0) {
      setFollowing([]);
      return;
    }

    const ids = data.map((f) => f.following_id);

    const { data: profiles } = await supabase
      .from("profiles")
      .select("id, name")
      .in("id", ids);

    const merged = data.map((f) => ({
      ...f,
      profiles: profiles?.find((p) => p.id === f.following_id),
    }));

    setFollowing(merged);
  };

  // 🔥 FETCH FOLLOWED PROJECTS (NEW)
  const fetchProjectFollowing = async (userId) => {
    const { data, error } = await supabase
      .from("project_followers")
      .select("*")
      .eq("user_id", userId);

    if (error) {
      console.log(error);
      return;
    }

    if (!data || data.length === 0) {
      setProjectFollowing([]);
      return;
    }

    const ids = data.map((p) => p.project_id);

    const { data: projects } = await supabase
      .from("projects")
      .select("id, title")
      .in("id", ids);

    const merged = data.map((p) => ({
      ...p,
      project: projects?.find((proj) => proj.id === p.project_id),
    }));

    setProjectFollowing(merged);
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Following</h2>

      {/* 🔥 USERS */}
      <h3>Users</h3>

      {following.length === 0 ? (
        <p>No users followed</p>
      ) : (
        following.map((f, index) => (
          <div
            key={index}
            onClick={() => navigate(`/user/${f.following_id}`)}
            style={{
              padding: "10px",
              marginTop: "10px",
              border: "1px solid gray",
              borderRadius: "8px",
              cursor: "pointer",
            }}
          >
            👤 {f.profiles?.name || "User"}
          </div>
        ))
      )}

      {/* 🔥 PROJECTS (NEW SECTION) */}
      <h3 style={{ marginTop: "30px" }}>Projects</h3>

      {projectFollowing.length === 0 ? (
        <p>No projects followed</p>
      ) : (
        projectFollowing.map((p, index) => (
          <div
            key={index}
            onClick={() => navigate(`/project/${p.project_id}`)} // ✅ NAVIGATE
            style={{
              padding: "10px",
              marginTop: "10px",
              border: "1px solid gray",
              borderRadius: "8px",
              cursor: "pointer",
            }}
          >
            🚀 {p.project?.title || "Project"}
          </div>
        ))
      )}
    </div>
  );
}
